// Elpa Game3D — demo model assets (generated; do not edit by hand).
//
// Two tiny hand-built glTF models the island-village demo loads at runtime so the
// SDK's glTF/GLB loader (`45-gltf.js`) runs on a live GPU, not just in tests:
//
//   * GEM_GLB_B64  — a faceted octahedron "crystal" as a base64 **.glb** binary
//                    container, loaded with `loadGLBBase64(GEM_GLB_B64)`.
//   * DIAMOND_GLTF — a hexagonal-bipyramid "diamond" as a **.gltf** JSON document
//                    with a `data:` base64 buffer, loaded with
//                    `loadGLTF(diamondGLTF(), 0)`.
//
// Regenerate with:  python3 scripts/gen_demo_models.py
// (octahedron + hex-bipyramid, flat-shaded, outward-wound, with NORMAL accessors).

let GEM_GLB_B64 = "";
let DIAMOND_GLTF_JSON = "{\"asset\":{\"version\":\"2.0\",\"generator\":\"elpa gen_demo_models\"},\"scene\":0,\"scenes\":[{\"nodes\":[0]}],\"nodes\":[{\"mesh\":0}],\"meshes\":[{\"primitives\":[{\"attributes\":{\"POSITION\":0,\"NORMAL\":1},\"indices\":2,\"material\":0}]}],\"materials\":[{\"name\":\"gold-gem\",\"pbrMetallicRoughness\":{\"baseColorFactor\":[0.95,0.78,0.3,1.0],\"metallicFactor\":0.9,\"roughnessFactor\":0.2},\"emissiveFactor\":[0.18,0.1,0.0]}],\"accessors\":[{\"bufferView\":0,\"componentType\":5126,\"count\":36,\"type\":\"VEC3\",\"min\":[-0.85,-1.0,-0.7361215932167728],\"max\":[0.85,1.25,0.7361215932167728]},{\"bufferView\":1,\"componentType\":5126,\"count\":36,\"type\":\"VEC3\"},{\"bufferView\":2,\"componentType\":5123,\"count\":36,\"type\":\"SCALAR\"}],\"bufferViews\":[{\"buffer\":0,\"byteOffset\":0,\"byteLength\":432},{\"buffer\":0,\"byteOffset\":432,\"byteLength\":432},{\"buffer\":0,\"byteOffset\":864,\"byteLength\":72}],\"buffers\":[{\"byteLength\":936,\"uri\":\"data:application/octet-stream;base64,\"}]}";

// Parse the embedded glTF document once, on demand.
function diamondGLTF() { return jsonParse(DIAMOND_GLTF_JSON); }
